      "site.823514cc3e398c5616": "Deep Work Sessions",
      "site.37b609cbd9f5fa3e12": "Define badges, evidence requirements, tiers, and reflection prompts.",
      "site.1d2d5cab11afa1cbf5": "Define rules, milestones, review checkpoints, and recovery steps.",
      "site.2e3028a78203dfb6f0": "Define terms, test examples, compare views, and invite the learner's position.",
